1	export type Cell = [x: number, y: number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<readonly [number, number]> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [0, -1],           [0, 1],
6	  [1, -1],  [1, 0],  [1, 1],
7	];
8	
9	function cellKey([x, y]: Cell): string {
10	  return `${x},${y}`;
11	}
12	
13	function neighborsOf([x, y]: Cell): Cell[] {
14	  return NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
15	}
16	
17	function survives(liveNeighborCount: number): boolean {
18	  return liveNeighborCount === 2 || liveNeighborCount === 3;
19	}
20	
21	function isBorn(liveNeighborCount: number): boolean {
22	  return liveNeighborCount === 3;
23	}
24	
25	export function nextGeneration(liveCells: Cell[]): Cell[] {
26	  const alive = new Set(liveCells.map(cellKey));
27	  const countLiveNeighbors = (cell: Cell) =>
28	    neighborsOf(cell).filter((n) => alive.has(cellKey(n))).length;
29	
30	  const candidates = new Map<string, Cell>();
31	  for (const cell of liveCells) {
32	    for (const candidate of [cell, ...neighborsOf(cell)]) {
33	      candidates.set(cellKey(candidate), candidate);
34	    }
35	  }
36	
37	  return [...candidates.values()].filter((cell) => {
38	    const count = countLiveNeighbors(cell);
39	    return alive.has(cellKey(cell)) ? survives(count) : isBorn(count);
40	  });
41	}
