1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("empty grid produces empty next generation — [] → []", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("single live cell dies from underpopulation — [(0,0)] → []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("two adjacent live cells both die from underpopulation — [(0,1),(1,1)] → []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("block (still life) remains unchanged — [(0,0),(1,0),(0,1),(1,1)] → same", () => {
15	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(result.sort()).toEqual(block.sort());
18	  });
19	  it("live cell with 2 neighbors survives (rule 2)", () => {
20	    // Horizontal row of 3: center cell (1,0) has 2 neighbors → survives;
21	    // ends (0,0) and (2,0) each have 1 neighbor → die from underpopulation.
22	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
23	    expect(result).toContainEqual([1, 0]);
24	    expect(result).not.toContainEqual([0, 0]);
25	    expect(result).not.toContainEqual([2, 0]);
26	  });
27	  it("live cell with 4 neighbors dies from overpopulation (rule 3)", () => {
28	    // + shape: center (1,1) has 4 live neighbors (up, down, left, right) → dies
29	    const result = nextGeneration([[1, 0], [0, 1], [1, 1], [2, 1], [1, 2]]);
30	    expect(result).not.toContainEqual([1, 1]);
31	  });
32	  it("dead cell with exactly 3 neighbors becomes alive (rule 4)", () => {
33	    // Dead cell (1,1) has 3 live neighbors: (0,0),(1,0),(0,1) → becomes alive
34	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
35	    expect(result).toContainEqual([1, 1]);
36	  });
37	  it("blinker oscillates: vertical [(0,0),(0,1),(0,2)] → horizontal [(-1,1),(0,1),(1,1)]", () => {
38	    const vertical: [number, number][] = [[0, 0], [0, 1], [0, 2]];
39	    const expected: [number, number][] = [[-1, 1], [0, 1], [1, 1]];
40	    const result = nextGeneration(vertical);
41	    expect(result.sort()).toEqual(expected.sort());
42	  });
43	  it("handles negative coordinates correctly", () => {
44	    // Block at negative coordinates — still life, should remain unchanged
45	    const block: [number, number][] = [[-5, -5], [-4, -5], [-5, -4], [-4, -4]];
46	    const result = nextGeneration(block);
47	    expect(result.sort()).toEqual(block.sort());
48	  });
49	});
